// Morning check: build a generic payload to check for today's cleanings
// Since this trigger has no webhook data, we create a default payload
const today = new Date().toISOString().split('T')[0];

return [{
  json: {
    uid: 'morning-check-' + today,
    checkoutDate: today,
    checkinDate: '',
    nights: 0,
    summary: 'Morning cleaning check',
    location: $env.NICK_DEFAULT_PROPERTY_ADDRESS || 'YOUR_PROPERTY_ADDRESS, Los Angeles, CA 90068',
    isToday: true,
    isTomorrow: false,
    readyForDispatch: true,
    isMorningCheck: true
  }
}];

// Build the cleaning dispatch message using AI-style personalization
const booking = $input.first().json;

const propertyAddress = booking.location || $env.NICK_DEFAULT_PROPERTY_ADDRESS || 'YOUR_PROPERTY_ADDRESS, Los Angeles, CA 90068';
const cleanerName = $env.NICK_CLEANER_NAME || 'Cleaner';
const hostName = 'Nick';
const checkoutDate = booking.checkoutDate || 'today';
const nights = booking.nights || 'a few';
const specialInstructions = $env.NICK_CLEANING_INSTRUCTIONS || '';

let urgency = '';
if (booking.isToday) {
  urgency = 'TODAY';
} else if (booking.isTomorrow) {
  urgency = 'TOMORROW';
}

let message = `Hi ${cleanerName}! 🧹 Cleaning needed ${urgency ? urgency : 'on ' + checkoutDate} at:\n\n`;
message += `${propertyAddress}\n\n`;

if (booking.isMorningCheck) {
  message += `This is your morning reminder — please check in when you're heading over.`;
} else {
  message += `Guest stayed ${nights} night${nights !== 1 ? 's' : ''}. `;
}

if (specialInstructions) {
  message += `\nSpecial notes: ${specialInstructions}\n`;
}

message += `\nPlease reply DONE when finished, or let me know if there are any issues. Thanks!`;

return [{
  json: {
    chat_id: $env.NICK_CLEANER_TELEGRAM_CHAT_ID || 'PLACEHOLDER_CHAT_ID',
    text: message,
    bookingUid: booking.uid || 'manual',
    checkoutDate: checkoutDate,
    dispatchedAt: new Date().toISOString()
  }
}];

